/* Optimize by nesting media queries inside selectors,
   combining :is() with nesting, and reducing repetition.
   Current code has 15+ top-level rules - target 5 or fewer. */
.dashboard {
  display: grid;
  grid-template-rows: auto 1fr;
  min-height: 100vh;
  background-color: #f8f9fa;
}
.dash-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 24px;
  background-color: white;
  border-bottom: 1px solid #dee2e6;
}
.dash-title {
  margin: 0;
  font-size: 20px;
  color: #212529;
}
.dash-nav {
  display: flex;
  gap: 4px;
}
.dash-link {
  color: #6c757d;
  text-decoration: none;
  padding: 8px 12px;
  border-radius: 4px;
}
.dash-link:hover {
  color: #212529;
  background-color: #f8f9fa;
}
.dash-link.active {
  color: #007bff;
  background-color: #e7f1ff;
}
.dash-main {
  padding: 24px;
}
.dash-widget {
  background-color: white;
  padding: 20px;
  border-radius: 8px;
  border: 1px solid #dee2e6;
}
@media (max-width: 768px) {
  .dash-header {
    flex-direction: column;
    gap: 12px;
  }
  .dash-nav {
    width: 100%;
  }
  .dash-main {
    padding: 12px;
  }
}

