.dashboard {
  display: grid;
  grid-template-rows: auto 1fr;
  min-height: 100vh;
  background-color: rgb(248, 249, 250);

  & .dash-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 16px 24px;
    background-color: rgb(255, 255, 255);
    border-bottom: 1px solid rgb(222, 226, 230);

    @media (max-width: 768px) {
      flex-direction: column;
      gap: 12px;
    }
  }

  & .dash-title {
    margin: 0;
    font-size: 20px;
    color: rgb(33, 37, 41);
  }

  & .dash-nav {
    display: flex;
    gap: 4px;

    @media (max-width: 768px) {
      width: 100%;
    }
  }

  & .dash-link {
    color: rgb(108, 117, 125);
    text-decoration: none;
    padding: 8px 12px;
    border-radius: 4px;

    &:hover {
      color: rgb(33, 37, 41);
      background-color: rgb(248, 249, 250);
    }

    &.active {
      color: rgb(0, 123, 255);
      background-color: rgb(231, 241, 255);
    }
  }

  & .dash-main {
    padding: 24px;

    @media (max-width: 768px) {
      padding: 12px;
    }
  }

  & .dash-widget {
    background-color: rgb(255, 255, 255);
    padding: 20px;
    border-radius: 8px;
    border: 1px solid rgb(222, 226, 230);
  }
}

